n                        //ClickOmniProd(true,'event10,event54','button:section:'+getVal+':',getHeading,pVal);\n                    } else if ($this.not(\"cta-preorder-button\") && $this.not(\"stock-grey-out\") && $this.hasClass('cta-button-sm-disabled')) {\n                        if (pVal == '' || typeof pVal == 'undefined') {\n                            pVal = $this.attr('data-digital-river-id');\n                        }\n                        if (getHeading == '' || typeof getHeading == 'undefined') {\n                            getHeading = $this.parents('a').siblings('a').text();\n                        }\n                        \n                        ClickOmniProd(true, 'event10,scAdd', 'button:section:' + getVal + ':', getHeading, pVal);\n                    } \n                });\n\n        // IMAGE ClickOmniTrack\n\n        $('.image a.imageLink img.responsive-image,.items .imageItem img').click(function() {\n            var $this = $(this);\n            var getVal = $this.attr('alt');\n            ClickOmniTrack(true, 'event10', 'img:section:', getVal);\n        });\n\n        // SUBNAV TRACK\n        $('.breadcrumb-element.persisting a[href*=\"#shop-all\"] span').click(function() {\n            getVal = \"Shop All\";\n            ClickOmniTrackNav(true, 'event10,event11', 'link:header:sub-nav:', getVal);\n        });\n\n\n        // PRODUCT Click\n\n        $('#shop-30series a[href*=\"/geforce/graphics-cards/30-series/rtx-3090\"] .notched-g').click(function() {\n            var getVal = \"GeForce RTX 3090\";\n            ClickOmniTrack(true, 'event10', 'link:section:SHOP NOW:RTX 30 SERIES:', getVal);\n        });\n        $('#shop-30series a[href*=\"/geforce/graphics-cards/30-series/rtx-3080\"] .notched-g').click(function() {\n            var getVal = \"GeForce RTX 3080\";\n            ClickOmniTrack(true, 'event10', 'link:section:SHOP NOW:RTX 30 SERIES:', getVal);\n        });\n        $('#shop-30series a[href*=\"/geforce/graphics-cards/30-s